def numRollsToTarget(n, k, target):
    MOD = 10**9 + 7
    dp = [0] * (target + 1); dp[0] = 1
    for _ in range(n):
        new_dp = [0] * (target + 1)
        for j in range(1, target + 1):
            for f in range(1, k + 1):
                if j - f >= 0: new_dp[j] = (new_dp[j] + dp[j-f]) % MOD
        dp = new_dp
    return dp[target]

